import{_ as e,o as r,c as a,a4 as i}from"./chunks/framework.BybBnFXO.js";const m=JSON.parse('{"title":"Silicates — Isolated Tetrahedra / Rings","description":"","frontmatter":{"title":"Silicates — Isolated Tetrahedra / Rings","mineralGroup":"silicates-isolated"},"headers":[],"relativePath":"mineral-groups/silicates-isolated.md","filePath":"mineral-groups/silicates-isolated.md","lastUpdated":1784177547000}'),d={name:"mineral-groups/silicates-isolated.md"};function s(l,t,o,n,c,h){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="silicates-—-isolated-tetrahedra-rings" tabindex="-1">Silicates — Isolated Tetrahedra / Rings <a class="header-anchor" href="#silicates-—-isolated-tetrahedra-rings" aria-label="Permalink to &quot;Silicates — Isolated Tetrahedra / Rings&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Isolated-tetrahedra structures (garnet, olivine, zircon type) host many high-refractive-index gems:</p><ul><li><strong>Garnet group</strong>: almandine, pyrope, spessartine, grossular, andradite, demantoid, tsavorite, color-change varieties</li><li><strong>Olivine group</strong>: peridot (forsterite–fayalite series)</li><li><strong>Zircon group</strong>: includes natural radiation damage over time Important ring silicates include tourmaline and cordierite (iolite).</li></ul><h2 id="formula-class" tabindex="-1">Formula Class <a class="header-anchor" href="#formula-class" aria-label="Permalink to &quot;Formula Class&quot;">​</a></h2><p>M₃Al₂(SiO₄)₃ / M₃(SiO₄) + Si₃O₉</p><h2 id="crystal-structure" tabindex="-1">Crystal Structure <a class="header-anchor" href="#crystal-structure" aria-label="Permalink to &quot;Crystal Structure&quot;">​</a></h2><p>In nesosilicates, [SiO₄]⁴⁻ tetrahedra are isolated (no oxygen sharing); cations (M²⁺, M³⁺) bridge the structure at interstices. Cyclosilicates contain [Si₃O₉]⁶⁻ (three-member) or [Si₆O₁₈]¹²⁻ (six-member) rings formed by tetrahedra linked corner-to-corner.</p><h2 id="representative-gem-species" tabindex="-1">Representative Gem Species <a class="header-anchor" href="#representative-gem-species" aria-label="Permalink to &quot;Representative Gem Species&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Gem</th><th>Formula</th><th>Subgroup</th></tr></thead><tbody><tr><td>Almandine / 铁铝榴石</td><td>Fe₃Al₂(SiO₄)₃</td><td>garnet (Al)</td></tr><tr><td>Pyrope / 镁铝榴石</td><td>Mg₃Al₂(SiO₄)₃</td><td>garnet (Al)</td></tr><tr><td>Spessartine / 锰铝榴石</td><td>Mn₃Al₂(SiO₄)₃</td><td>garnet (Al)</td></tr><tr><td>Grossular / 钙铝榴石</td><td>Ca₃Al₂(SiO₄)₃</td><td>garnet (Al)</td></tr><tr><td>Tsavorite / 沙弗莱</td><td>Ca₃Al₂(SiO₄)₃ + V,Cr</td><td>grossular</td></tr><tr><td>Demantoid / 翠榴石</td><td>Ca₃Fe₂(SiO₄)₃ + Cr</td><td>garnet (Fe)</td></tr><tr><td>Peridot / 橄榄石</td><td>(Mg,Fe)₂SiO₄</td><td>olivine</td></tr><tr><td>Zircon / 锆石</td><td>ZrSiO₄</td><td>zircon</td></tr><tr><td>Topaz / 黄玉</td><td>Al₂SiO₄(F,OH)₂</td><td>topaz</td></tr><tr><td>Chrysoberyl / 金绿宝石</td><td>BeAl₂O₄</td><td>chrysoberyl</td></tr><tr><td>Tourmaline (Elbaite) / 碧玺</td><td>Na(Li,Al)₃Al₆(BO₃)₃Si₆O₁₈(OH)₃</td><td>cyclosilicate</td></tr><tr><td>Iolite (Cordierite) / 堇青石</td><td>Mg₂Al₄Si₅O₁₈</td><td>cyclosilicate</td></tr></tbody></table><p><em>See the <a href="./intro.html">mineral group overview</a>.</em></p>',11)])])}const p=e(d,[["render",s]]);export{m as __pageData,p as default};
